// ─── Demo modal ─────────────────────────────────────────────────────────
function DemoModal({ initialPlan = "", goldBtn, onClose }) {
  const OWNER_EMAIL = "nikimodiai@gmail.com";
  const [f, setF] = useState({ name: "", store: "", address: "", city: "", pincode: "", phone: "", waBusiness: "", plan: initialPlan });
  const [errors, setErrors] = useState({});
  const [sent, setSent] = useState(false);
  useEffect(() => {
    const esc = (e) => e.key === "Escape" && onClose();
    document.addEventListener("keydown", esc);
    document.body.style.overflow = "hidden";
    return () => { document.removeEventListener("keydown", esc); document.body.style.overflow = ""; };
  }, [onClose]);
  const set = (k) => (e) => setF((p) => ({ ...p, [k]: e.target.value }));
  const validate = () => {
    const er = {};
    if (!f.name.trim()) er.name = "Please enter your name.";
    if (!f.store.trim()) er.store = "Please enter your jewellery store.";
    if (!f.city.trim()) er.city = "City is required.";
    if (!/^\d{6}$/.test(f.pincode.trim())) er.pincode = "Enter a valid 6-digit pincode.";
    if (!/^[\d+\s-]{7,15}$/.test(f.phone.trim())) er.phone = "Enter a valid phone number.";
    setErrors(er);
    return Object.keys(er).length === 0;
  };
  const submit = () => {
    if (!validate()) return;
    const subject = `New Swarnix Demo Request — ${f.store.trim()} (${f.city.trim()})`;
    const lines = ["A new demo request has come in from the Swarnix website.", "",
      `Name:                 ${f.name.trim()}`, `Jewellery Store:      ${f.store.trim()}`,
      `Address:              ${f.address.trim() || "—"}`, `City:                 ${f.city.trim()}`,
      `Pincode:              ${f.pincode.trim()}`, `Phone Number:         ${f.phone.trim()}`,
      `WhatsApp Business No.: ${f.waBusiness.trim() || "—"}`, `Plan of Interest:     ${f.plan || "Not specified"}`,
      "", "— Sent from the Swarnix website demo form."];
    window.location.href = `mailto:${OWNER_EMAIL}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(lines.join("\n"))}`;
    setSent(true);
  };
  const field = (label, key, { required = false, type = "text", placeholder = "" } = {}) => (
    <div style={{ marginBottom: 16 }}>
      <label style={{ display: "block", fontFamily: sans, fontSize: 12, fontWeight: 500, letterSpacing: "0.08em", textTransform: "uppercase", color: C.creamMute, marginBottom: 7 }}>
        {label} {required && <span style={{ color: C.gold }}>*</span>}{!required && <span style={{ color: "rgba(245,239,226,0.35)", textTransform: "none", letterSpacing: 0, fontWeight: 300 }}> (optional)</span>}
      </label>
      <input type={type} value={f[key]} onChange={set(key)} placeholder={placeholder}
        style={{ width: "100%", fontFamily: sans, fontSize: 15, fontWeight: 300, color: C.cream, background: "rgba(8,42,41,0.6)", border: `1px solid ${errors[key] ? "#D98A6A" : C.tealLine}`, borderRadius: 3, padding: "12px 14px", outline: "none" }}
        onFocus={(e) => (e.target.style.borderColor = C.gold)} onBlur={(e) => (e.target.style.borderColor = errors[key] ? "#D98A6A" : C.tealLine)} />
      {errors[key] && <div style={{ fontFamily: sans, fontSize: 12.5, color: "#E5A98E", marginTop: 5 }}>{errors[key]}</div>}
    </div>
  );
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 200, background: "rgba(4,15,15,0.7)", backdropFilter: "blur(5px)", display: "flex", alignItems: "flex-start", justifyContent: "center", padding: "40px 18px", overflowY: "auto" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "100%", maxWidth: 560, background: C.teal, borderRadius: 8, boxShadow: "0 44px 100px rgba(0,0,0,0.55)", border: `1px solid ${C.tealLine}`, overflow: "hidden", animation: "kpop .35s cubic-bezier(.2,.7,.2,1)" }}>
        <div style={{ background: `linear-gradient(135deg, ${C.tealSoft} 0%, ${C.tealDark} 100%)`, padding: "28px 30px", position: "relative", borderBottom: `1px solid ${C.tealLine}` }}>
          <button onClick={onClose} aria-label="Close" style={{ position: "absolute", top: 18, right: 20, background: "none", border: "none", color: C.creamSoft, fontSize: 26, lineHeight: 1, cursor: "pointer" }}>×</button>
          <Sparkle s={18} style={{ marginBottom: 8 }} />
          <div style={{ fontFamily: serif, fontSize: 25, fontWeight: 600, color: C.cream, lineHeight: 1.1 }}>Book Your <span style={{ fontStyle: "italic", color: C.gold }}>Free Demo</span></div>
          <div style={{ fontFamily: sans, fontSize: 12.5, fontWeight: 300, color: C.creamMute, marginTop: 4 }}>A 30-minute walkthrough. No commitment.</div>
        </div>
        {sent ? (
          <div style={{ padding: "44px 34px", textAlign: "center" }}>
            <div style={{ width: 56, height: 56, borderRadius: "50%", background: goldGrad, margin: "0 auto 22px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, color: C.tealDark }}>✓</div>
            <h3 style={{ fontFamily: serif, fontSize: 27, fontWeight: 600, color: C.cream, margin: "0 0 12px" }}>Your email is ready to send.</h3>
            <p style={{ fontFamily: sans, fontSize: 15, fontWeight: 300, color: C.creamSoft, lineHeight: 1.7, margin: "0 0 26px" }}>Your mail app should have opened with the details filled in and addressed to our team. Just press send, and we'll be in touch shortly. If nothing opened, you can write to us at <span style={{ color: C.gold }}>{OWNER_EMAIL}</span>.</p>
            <button onClick={onClose} style={{ ...goldBtn, padding: "13px 34px" }}>Close</button>
          </div>
        ) : (
          <div style={{ padding: "28px 30px 32px" }}>
            {field("Your Name", "name", { required: true, placeholder: "e.g. Rajesh Mehta" })}
            {field("Jewellery Store", "store", { required: true, placeholder: "e.g. Mehta Jewellers" })}
            {field("Address", "address", { placeholder: "Shop no., street, area" })}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
              {field("City", "city", { required: true, placeholder: "e.g. Mumbai" })}
              {field("Pincode", "pincode", { required: true, placeholder: "6-digit" })}
            </div>
            {field("Phone Number", "phone", { required: true, type: "tel", placeholder: "+91 ..." })}
            {field("WhatsApp Business Number", "waBusiness", { type: "tel", placeholder: "+91 ..." })}
            <div style={{ marginBottom: 22 }}>
              <label style={{ display: "block", fontFamily: sans, fontSize: 12, fontWeight: 500, letterSpacing: "0.08em", textTransform: "uppercase", color: C.creamMute, marginBottom: 7 }}>Plan You're Interested In <span style={{ color: "rgba(245,239,226,0.35)", textTransform: "none", letterSpacing: 0, fontWeight: 300 }}>(optional)</span></label>
              <select value={f.plan} onChange={set("plan")} style={{ width: "100%", fontFamily: sans, fontSize: 15, fontWeight: 300, color: f.plan ? C.cream : C.creamMute, background: "rgba(8,42,41,0.6)", border: `1px solid ${C.tealLine}`, borderRadius: 3, padding: "12px 14px", outline: "none", cursor: "pointer" }}>
                <option value="" style={{ color: "#000" }}>No preference yet</option>
                <option value="Trial" style={{ color: "#000" }}>Trial</option>
                <option value="Starter" style={{ color: "#000" }}>Starter</option>
                <option value="Professional" style={{ color: "#000" }}>Professional</option>
                <option value="Enterprise" style={{ color: "#000" }}>Enterprise</option>
              </select>
            </div>
            <button onClick={submit} className="k-gold-btn" style={{ ...goldBtn, width: "100%", padding: "15px" }}>Send My Demo Request</button>
            <p style={{ fontFamily: sans, fontSize: 12, fontWeight: 300, color: C.creamMute, textAlign: "center", marginTop: 14, lineHeight: 1.6 }}>Fields marked <span style={{ color: C.gold }}>*</span> are required. Your details go straight to our team — nothing is shared.</p>
          </div>
        )}
      </div>
      <style>{`@keyframes kfadein{from{opacity:0;transform:translateX(-50%) translateY(4px)}to{opacity:1;transform:translateX(-50%) translateY(0)}} @keyframes kpop{from{opacity:0;transform:translateY(20px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}`}</style>
    </div>
  );
}
